message.content:
{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires a complex logical chain through 45 rules. I will split the task into rule extraction/mapping and logical inference.",
  "helpers": [
    {
      "label": "rule_mapper",
      "instructions": "Analyze the provided 45 rules of the board game. Identify and list every rule that mentions the butterfly, the fish, or any intermediate entities that could link the butterfly to the fish. Create a directed graph or a sequential list of rule-based transitions that connect the butterfly to other game elements."
    },
    {
      "label": "logic_engine",
      "instructions": "Using the rule transitions provided by the rule mapper, attempt to construct a logical chain starting from the butterfly and ending at the fish. Determine if there is a definitive sequence of rules that results in the butterfly revealing a secret to the fish. If the chain is broken, incomplete, or if the rules do not provide enough information to confirm the action, conclude that the outcome is unknown."
    }
  ],
  "synthesis_brief": "The parent agent will take the rule transitions from the rule mapper and apply them to the logic engine's reasoning process. The final answer must be 'unknown' if the logical chain cannot be completed with certainty based strictly on the provided rules."
}

